import{_ as t,o as l,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"スケーラーリファレンス (Scaler Reference)","description":"","frontmatter":{},"headers":[],"relativePath":"ja/scalers/reference.md","filePath":"ja/scalers/reference.md"}'),d={name:"ja/scalers/reference.md"};function o(n,e,i,s,c,g){return l(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="スケーラーリファレンス-scaler-reference" tabindex="-1"><i class="ph ph-sliders"></i> スケーラーリファレンス (Scaler Reference) <a class="header-anchor" href="#スケーラーリファレンス-scaler-reference" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-sliders&quot;&gt;&lt;/i&gt; スケーラーリファレンス (Scaler Reference)&quot;">​</a></h1><p>Web Adaptive Performance には、専用のスケーラー（最適化モジュール）のセットが含まれています。インデクサー（Indexer）は、視覚的な影響度（<code>Visual Impact</code>）と現在のボトルネックの種類（<code>Target</code>: CPUまたはGPU）に基づいて、実装するスケーラーを自動的に選択します。</p><h2 id="互換性マトリックス" tabindex="-1">互換性マトリックス <a class="header-anchor" href="#互換性マトリックス" aria-label="Permalink to &quot;互換性マトリックス&quot;">​</a></h2><p>以下は、互換性マトリックスと利用可能なすべてのモジュールの説明です。</p><table tabindex="0"><thead><tr><th style="text-align:left;">スケーラー</th><th style="text-align:left;">パイプライン</th><th style="text-align:left;">Target</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Resolution</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">レンダリング解像度を下げ、GPUのフィルレート（Fillrate）の負荷を根本的に減らします。<em>詳細は以下を参照してください。</em></td></tr><tr><td style="text-align:left;"><strong>Shadows Quality</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">シャドウを段階的に無効にします。<br><strong>URP</strong>では、最初にソフトシャドウを無効にし、次に追加ライトのシャドウを無効にし、最後にメインのシャドウを無効にします。<br><strong>BiRP</strong>では、完全に無効にする前に、シャドウを <code>Hard Only</code> モードに切り替えます。</td></tr><tr><td style="text-align:left;"><strong>Shadow Cascades</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU/GPU</td><td style="text-align:left;">シャドウのカスケー​​ド数を減らします。CPUのドローコール（Draw Calls）とGPUの負荷を軽減します。</td></tr><tr><td style="text-align:left;"><strong>Shadow Distance</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">シャドウの描画距離（Draw Distance）を短くします。</td></tr><tr><td style="text-align:left;"><strong>Shadow Resolution</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">シャドウマップの解像度を下げます。</td></tr><tr><td style="text-align:left;"><strong>Anti Aliasing</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">アンチエイリアス（MSAA）の品質を、完全に無効になるまで下げます。</td></tr><tr><td style="text-align:left;"><strong>LOD Bias</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">カメラからのより短い距離で、低ポリゴンのLODモデルに切り替えるようUnityに強制します。</td></tr><tr><td style="text-align:left;"><strong>Camera Clip</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">ターゲットカメラの <code>Far Clip Plane</code> パラメータを下げ、遠くのオブジェクトをレンダリングから除外します。</td></tr><tr><td style="text-align:left;"><strong>Layer Culling</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU</td><td style="text-align:left;">特定のオブジェクトレイヤーのカリング距離（Culling Distance）を比例的に減らします。</td></tr><tr><td style="text-align:left;"><strong>Physics Step</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU</td><td style="text-align:left;">物理計算の頻度を減らします。ブラウザで重い物理負荷がかかった際に、パフォーマンスを節約します。</td></tr><tr><td style="text-align:left;"><strong>LUT</strong></td><td style="text-align:left;"><code>URPのみ</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Color Grading LUTテーブルのサイズを最小限に縮小します。</td></tr><tr><td style="text-align:left;"><strong>Mesh LOD Threshold</strong></td><td style="text-align:left;"><code>Unity 6+</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">積極的なLOD変更のために、Unity 6.2で導入された <code>meshLodThreshold</code> パラメータを変更します。</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Physics Step Scaler に関する注意</p><p>物理スケーラーは <code>Time.fixedDeltaTime</code> パラメータを直接変更します。キャラクターコントローラーやゲームのメカニクスが補間（Interpolation）なしの固定物理フレームに厳密に依存している場合、低品質レベルではオブジェクトの動きがカクつく（スタッターする）可能性があります。</p></div><div class="tip custom-block"><p class="custom-block-title">スケーラー設定のリセット</p><p>スケーラーのパラメータ（<code>Min Bound</code> や <code>Max Level</code> の変更など）を試した後、デフォルト値に戻したい場合は、<em>Project Settings</em> ウィンドウでそのスイッチをオフにして再度オンにするだけです。プラグインは自動的にベース設定でモジュールを再作成します。</p></div><h2 id="深掘り-resolution-scaler" tabindex="-1">深掘り: Resolution Scaler <a class="header-anchor" href="#深掘り-resolution-scaler" aria-label="Permalink to &quot;深掘り: Resolution Scaler&quot;">​</a></h2><p>これはプラグイン内で最も強力なツールであり、最大のFPS向上を保証します。その動作は、アクティブなパイプラインによって大きく異なります。</p><h3 id="urp-universal-render-pipeline-モード" tabindex="-1">URP (Universal Render Pipeline) モード <a class="header-anchor" href="#urp-universal-render-pipeline-モード" aria-label="Permalink to &quot;URP (Universal Render Pipeline) モード&quot;">​</a></h3><p>URPでは、スケーリングは完璧に機能します。プラグインは <code>UniversalRenderPipelineAsset</code> の <code>renderScale</code> プロパティに直接介入します。URPはスケールされた3Dワールドの上にCanvasをレンダリングできるため、インターフェース（UI）は自動的に鮮明に保たれます。</p><h3 id="birp-built-in-render-pipeline-モード" tabindex="-1">BiRP (Built-in Render Pipeline) モード <a class="header-anchor" href="#birp-built-in-render-pipeline-モード" aria-label="Permalink to &quot;BiRP (Built-in Render Pipeline) モード&quot;">​</a></h3><p>歴史的に、BiRPにはインターフェースを壊したりグリッチ（FBO Feedback Loop）を引き起こしたりすることなくWebGLで機能する組み込みのRender Scale設定がありません。WebAPは2つの独自の戦略を提供することでこれを解決します。</p><h4 id="モード-1-nativebrowserscaling-ネイティブブラウザスケーリング" tabindex="-1">モード 1: NativeBrowserScaling (ネイティブブラウザスケーリング) <a class="header-anchor" href="#モード-1-nativebrowserscaling-ネイティブブラウザスケーリング" aria-label="Permalink to &quot;モード 1: NativeBrowserScaling (ネイティブブラウザスケーリング)&quot;">​</a></h4><p>プラグインは、ネイティブループスプーフィング（ブラウザの <code>devicePixelRatio</code> パラメータへの注入）を介して <code>&lt;canvas&gt;</code> HTML要素を直接スケールします。</p><ul><li><strong>長所:</strong> 最高のパフォーマンス。GPU側のオーバーヘッドはゼロです。</li><li><strong>短所:</strong> ゲームのインターフェースが3Dグラフィックと共にぼやけます。このモードはコンパイルされたWebGLビルドでのみ機能します（Unity Editor内では変更は表示されません）。</li></ul><h4 id="モード-2-rendertexturescaling" tabindex="-1">モード 2: RenderTextureScaling <a class="header-anchor" href="#モード-2-rendertexturescaling" aria-label="Permalink to &quot;モード 2: RenderTextureScaling&quot;">​</a></h4><p>プラグインは、ターゲットカメラのレンダリングを圧縮された共有テクスチャにリダイレクトし、非表示の合成カメラ（Compositor Camera）を使用して画像を表示します。</p><ul><li><strong>長所:</strong> 3Dワールドはスケールされますが、UI（テキスト、ボタン）は鮮明なままです。</li><li><strong>短所:</strong> Blit操作（テクスチャを画面にコピーする処理）により、GPUにわずかな負荷が追加されます。</li></ul><div class="info custom-block"><p class="custom-block-title">マウスクリック (Raycasts) の修正</p><p>RenderTextureScalingを使用する場合、仮想画面座標が圧縮されます。3Dオブジェクトへのマウスクリックが引き続き正しく機能するように、プラグインは自動的にターゲットカメラの標準的な <code>PhysicsRaycaster</code> および <code>Physics2DRaycaster</code> コンポーネントを、カスタムの <code>WebScaledPhysicsRaycaster</code> コンポーネントに置き換えます。光線の精度は、どのスケールでも完璧に維持されます。</p></div><h2 id="uiの明瞭さを維持する方法-birp-rendertexturescaling用" tabindex="-1">UIの明瞭さを維持する方法 (BiRP RenderTextureScaling用) <a class="header-anchor" href="#uiの明瞭さを維持する方法-birp-rendertexturescaling用" aria-label="Permalink to &quot;UIの明瞭さを維持する方法 (BiRP RenderTextureScaling用)&quot;">​</a></h2><p>RenderTextureScalingを使用してBiRPで3Dグラフィックをスケーリングしながら、鮮明なインターフェースを維持するには、Canvasを正しく設定する必要があります。次の2つのオプションのいずれかを選択してください：</p><h3 id="オプション-1-screen-space-overlay-推奨" tabindex="-1">オプション 1: Screen Space - Overlay (推奨) <a class="header-anchor" href="#オプション-1-screen-space-overlay-推奨" aria-label="Permalink to &quot;オプション 1: Screen Space - Overlay (推奨)&quot;">​</a></h3><p>最も簡単で信頼性の高い方法です。プラグインがすべての作業を自動的に処理します。</p><ol><li>シーンの階層で <strong>Canvas</strong> を選択します。</li><li>Canvasコンポーネントで、<strong>Render Mode</strong> を <code>Screen Space - Overlay</code> に設定します。<br><em>結果:</em> Unityは、圧縮された3Dワールドの上に、100%ネイティブな解像度でインターフェースをレンダリングします。</li></ol><h3 id="オプション-2-screen-space-camera-複雑なレイヤー用" tabindex="-1">オプション 2: Screen Space - Camera (複雑なレイヤー用) <a class="header-anchor" href="#オプション-2-screen-space-camera-複雑なレイヤー用" aria-label="Permalink to &quot;オプション 2: Screen Space - Camera (複雑なレイヤー用)&quot;">​</a></h3><p>3Dモデル、パーティクル、およびUIを混在させる必要がある場合に使用されます。レンダリングを2つのカメラに分ける必要があります。</p><ol><li><strong>メインカメラ (3D):</strong> そのタグがスケーラーの <code>Target Tags</code> 配列に指定されていることを確認してください。<code>Culling Mask</code> フィールドで <strong>UI</strong> レイヤーのチェックを外します。<code>Depth</code> を <code>0</code> に設定します。</li><li><strong>UIカメラ (新規):</strong> インターフェースをレンダリングするための新しいカメラを作成します。そのタグをスケーラー設定に<strong>追加しないでください</strong>。 <ul><li><code>Clear Flags</code> を <code>Depth Only</code> に設定します（カメラが3Dの背景を消去しないようにするため）。</li><li><code>Culling Mask</code> を <strong>UI</strong> レイヤーのみに設定します。</li><li><code>Depth</code> を <code>1</code> に設定します（メインカメラよりも大きくします）。</li></ul></li><li><strong>Canvas設定:</strong> <strong>Render Mode</strong> を <code>Screen Space - Camera</code> に設定し、新しいUIカメラを <code>Render Camera</code> スロットにドラッグします。</li></ol>',28)])])}const P=t(d,[["render",o]]);export{h as __pageData,P as default};
